<script lang="ts">import {onMount} from 'svelte'; import AppShell from '$lib/components/AppShell.svelte'; import PageHeader from '$lib/components/PageHeader.svelte';import AdminSection from '$lib/components/AdminSection.svelte'; import AdminStatCard from '$lib/components/AdminStatCard.svelte'; import DataTable from '$lib/components/DataTable.svelte'; import StatusBadge from '$lib/components/StatusBadge.svelte'; import {currentUser} from '$lib/stores/user';import {fetchAdminSystem,fetchAdminEmailLogs,fetchAdminNotifications,fetchAdminExports,testAdminSmtp,testAdminTelegram,testAdminYoutube,testAdminStripe,fetchAdminSmoke,type AdminSmoke} from '$lib/api';let system:any={};let logs:any[]=[];let notifs:any={};let exportsData:any[]=[];let smoke:AdminSmoke|null=null;let smtpTo='';let chatId='';let loading:Record<string,boolean>={};let latest:Record<string,string>={};let history:{key:string;ok:boolean;message:string;date:string}[]=[];let loadingGlobal=false;let errorGlobal='';const load=async()=>{loadingGlobal=true;errorGlobal='';try{system=await fetchAdminSystem();logs=(await fetchAdminEmailLogs()).logs||[];notifs=await fetchAdminNotifications();exportsData=(await fetchAdminExports()).exports||[]}catch(e:any){errorGlobal=e.message||'Erreur'}finally{loadingGlobal=false}};const record=(k:string,ok:boolean,m:string)=>{latest[k]=m;history=[{key:k,ok,message:m,date:new Date().toISOString()},...history].slice(0,20)};const run=async(k:string)=>{if(k==='smtp'&&!smtpTo.trim()){record(k,false,'Renseigne un email destinataire avant de tester SMTP.');return;}loading[k]=true;try{const r= k==='smtp'?await testAdminSmtp({to:smtpTo}):k==='telegram'?await testAdminTelegram({chat_id:chatId||undefined}):k==='youtube'?await testAdminYoutube():await testAdminStripe();record(k,Boolean(r.ok ?? r.sent),r.message ?? r.reason ?? 'ok');}catch(e:any){record(k,false,e.message||'error')}finally{loading[k]=false}};const runSmoke=async()=>{smoke=await fetchAdminSmoke()}; onMount(load);</script>
<AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Admin ops" subtitle="Cockpit d'exploitation"/><button on:click={load}>Refresh</button>{#if loadingGlobal}<p>Chargement global…</p>{/if}{#if errorGlobal}<p>{errorGlobal}</p>{/if}
<AdminSection title="Tests d'intégration"><div class="g"><AdminStatCard label="SMTP" value={system?.integrations?.smtp ?? 'not_configured'} status={system?.integrations?.smtp ?? 'not_configured'} hint={latest.smtp ?? ''}/><input bind:value={smtpTo} placeholder="Destinataire test"/><button disabled={loading.smtp} on:click={()=>run('smtp')}>Validation SMTP</button><AdminStatCard label="Telegram" value={system?.integrations?.telegram ?? 'not_configured'} status={system?.integrations?.telegram ?? 'not_configured'} hint={latest.telegram ?? ''}/><input bind:value={chatId} placeholder="Chat ID optionnel"/><button disabled={loading.telegram} on:click={()=>run('telegram')}>Test Telegram</button><AdminStatCard label="YouTube API" value={system?.integrations?.youtube ?? 'not_configured'} status={system?.integrations?.youtube ?? 'not_configured'} hint={latest.youtube ?? ''}/><button disabled={loading.youtube} on:click={()=>run('youtube')}>Tester YouTube</button><AdminStatCard label="Stripe" value={system?.integrations?.stripe ?? 'not_configured'} status={system?.integrations?.stripe ?? 'not_configured'} hint={latest.stripe ?? ''}/><button disabled={loading.stripe} on:click={()=>run('stripe')}>Tester Stripe</button></div></AdminSection>
<AdminSection title="Smoke interne"><button on:click={runSmoke}>Lancer smoke</button>{#if smoke}<p>ok: <StatusBadge status={smoke.ok?'ok':'error'} /></p><DataTable columns={[{key:'check',label:'Check'},{key:'status',label:'Status',type:'status'}]} rows={Object.entries(smoke.checks||{}).map(([check,status])=>({check,status}))} />{/if}</AdminSection>
<AdminSection title="Résultats des tests"><DataTable columns={[{key:'key',label:'Test'},{key:'ok',label:'OK'},{key:'message',label:'Message'},{key:'date',label:'Date',type:'date'}]} rows={history} /></AdminSection>
{/if}</AppShell><style>.g{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:.6rem}</style>
